## useTransition — Non-Urgent State Updates

```jsx
import { useTransition, useState } from 'react';

function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  function handleChange(e) {
    // Urgent: update the input immediately
    setQuery(e.target.value);

    // Non-urgent: re-render the expensive results list
    startTransition(() => {
      setResults(expensiveFilter(e.target.value));
    });
  }

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending && <Spinner />}
      <ResultsList items={results} />
    </>
  );
}
```

**When to use:**
- Tab switching that re-renders a large list
- Search/filter with synchronous data
- Route transitions with expensive components

**When NOT to use:**
- Async operations (use `useDeferredValue` for those)
- Animations — transitions can be interrupted

## useDeferredValue — Defer Expensive Renders

```jsx
import { useDeferredValue, useMemo } from 'react';

function FilteredList({ query }) {
  // deferredQuery lags behind query while the input stays snappy
  const deferredQuery = useDeferredValue(query);
  const isStale = deferredQuery !== query;

  const filteredItems = useMemo(
    () => items.filter(item => item.name.includes(deferredQuery)),
    [deferredQuery]
  );

  return (
    <div style={{ opacity: isStale ? 0.6 : 1, transition: 'opacity 0.2s' }}>
      {filteredItems.map(item => <Item key={item.id} {...item} />)}
    </div>
  );
}
```

**useTransition vs useDeferredValue:**
| | useTransition | useDeferredValue |
|---|---|---|
| What you control | state setter | derived value |
| Has isPending | ✓ | needs manual stale check |
| Use when | you own the setter | you receive a prop/value |

## use() Hook (React 19)

### Reading a Promise
```jsx
import { use, Suspense } from 'react';

// Server Component passes a Promise to a Client Component
async function UserPage({ id }) {
  const userPromise = fetch(`/api/users/${id}`).then(r => r.json());
  return (
    <Suspense fallback={<Skeleton />}>
      <UserProfile userPromise={userPromise} />
    </Suspense>
  );
}

// Client Component
'use client';
function UserProfile({ userPromise }) {
  const user = use(userPromise); // suspends until resolved
  return <h1>{user.name}</h1>;
}
```

### Reading Context conditionally
```jsx
import { use } from 'react';

// Unlike useContext, use() can be called inside if/else/loops
function ConditionalTheme({ dark }) {
  if (!dark) return <LightVariant />;
  const theme = use(ThemeContext); // OK — use() is flexible
  return <DarkVariant theme={theme} />;
}
```

**Rules:**
- Wrap `use(promise)` in `<Suspense>` — it suspends during fetch
- Wrap `<Suspense>` in `<ErrorBoundary>` — it throws on rejection
- `use()` replaces `useEffect + useState` for async data in many cases

## React Server Actions

### Define a Server Action
```ts
// app/actions/user.ts
'use server';
import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';

export async function updateUser(formData: FormData) {
  const name = formData.get('name') as string;
  // Validate
  if (!name || name.length < 2) {
    return { error: 'Name must be at least 2 characters' };
  }
  await db.users.update({ where: { id: userId }, data: { name } });
  revalidatePath('/profile');
  // return state or redirect
}
```

### Use in a form (progressive enhancement)
```tsx
// Works without JS — native form submission
<form action={updateUser}>
  <input name="name" />
  <button type="submit">Save</button>
</form>
```

### With useActionState (React 19)
```tsx
'use client';
import { useActionState } from 'react';

function EditForm() {
  const [state, action, isPending] = useActionState(updateUser, null);
  return (
    <form action={action}>
      <input name="name" />
      {state?.error && <p>{state.error}</p>}
      <button disabled={isPending}>{isPending ? 'Saving...' : 'Save'}</button>
    </form>
  );
}
```

**Security:** Server Actions are automatically protected against CSRF. Never trust client-supplied IDs — always validate server-side ownership.

## useOptimistic — Instant UI Feedback

```tsx
'use client';
import { useOptimistic, useTransition } from 'react';

function LikeButton({ post }: { post: Post }) {
  const [optimisticPost, addOptimistic] = useOptimistic(
    post,
    (currentState, liked: boolean) => ({
      ...currentState,
      liked,
      likeCount: currentState.likeCount + (liked ? 1 : -1),
    })
  );

  const [, startTransition] = useTransition();

  async function handleLike() {
    startTransition(async () => {
      // Show immediately
      addOptimistic(!optimisticPost.liked);
      // Sync to server (reverts automatically on error)
      await toggleLike(post.id);
    });
  }

  return (
    <button onClick={handleLike}>
      {optimisticPost.liked ? '❤️' : '🤍'} {optimisticPost.likeCount}
    </button>
  );
}
```

**Rules:**
- Always wrap in `startTransition` — optimistic updates are non-urgent
- The state reverts automatically when the async action settles
- Show a visual diff (opacity, border) while in optimistic state

## Compound Component Pattern

```tsx
import { createContext, useContext, useState } from 'react';

// 1. Context
interface TabsCtx { active: string; setActive: (id: string) => void; }
const TabsContext = createContext<TabsCtx | null>(null);
const useTabs = () => {
  const ctx = useContext(TabsContext);
  if (!ctx) throw new Error('Must be used within <Tabs>');
  return ctx;
};

// 2. Parent — owns state
function Tabs({ defaultValue, children }: { defaultValue: string; children: React.ReactNode }) {
  const [active, setActive] = useState(defaultValue);
  return <TabsContext.Provider value={{ active, setActive }}>{children}</TabsContext.Provider>;
}

// 3. Sub-components — consume context
Tabs.List = function TabsList({ children }: { children: React.ReactNode }) {
  return <div role="tablist">{children}</div>;
};

Tabs.Trigger = function TabsTrigger({ value, children }: { value: string; children: React.ReactNode }) {
  const { active, setActive } = useTabs();
  return (
    <button role="tab" aria-selected={active === value} onClick={() => setActive(value)}>
      {children}
    </button>
  );
};

Tabs.Content = function TabsContent({ value, children }: { value: string; children: React.ReactNode }) {
  const { active } = useTabs();
  return active === value ? <div role="tabpanel">{children}</div> : null;
};

// Usage — consumer controls layout
<Tabs defaultValue="profile">
  <Tabs.List>
    <Tabs.Trigger value="profile">Profile</Tabs.Trigger>
    <Tabs.Trigger value="settings">Settings</Tabs.Trigger>
  </Tabs.List>
  <Tabs.Content value="profile"><ProfileForm /></Tabs.Content>
  <Tabs.Content value="settings"><SettingsForm /></Tabs.Content>
</Tabs>
```

## React.memo / useMemo / useCallback — Decision Guide

### React.memo — skip re-render when props didn't change
```tsx
// ✅ Good: expensive list item with stable props
const ExpensiveRow = React.memo(function ExpensiveRow({ item, onDelete }) {
  // only re-renders if item or onDelete reference changes
  return <tr>...</tr>;
});

// ❌ Pointless: cheap component — memo cost > savings
const Label = React.memo(({ text }) => <span>{text}</span>);
```

### useMemo — cache expensive computation
```tsx
// ✅ Expensive: large dataset sort/filter
const sorted = useMemo(
  () => [...data].sort((a, b) => a.name.localeCompare(b.name)),
  [data] // only recompute when data changes
);

// ❌ Pointless: trivial computation
const doubled = useMemo(() => count * 2, [count]);
```

### useCallback — stable function reference
```tsx
// ✅ Needed: passed to React.memo child or used as useEffect dep
const handleDelete = useCallback((id: string) => {
  setItems(prev => prev.filter(i => i.id !== id));
}, []);

// ❌ Pointless: function not passed to memoized child
const handleClick = useCallback(() => setOpen(true), []);
```

**Decision rule:**
1. Profile first — Chrome DevTools → React Profiler
2. Find the component that renders when it shouldn't
3. Add `React.memo` + `useCallback` for its callbacks
4. Add `useMemo` only if the profiler shows the computation is expensive

## Error Boundaries

### Using react-error-boundary (recommended)
```tsx
import { ErrorBoundary } from 'react-error-boundary';

function ErrorFallback({ error, resetErrorBoundary }: FallbackProps) {
  return (
    <div role="alert">
      <p>Something went wrong:</p>
      <pre>{error.message}</pre>
      <button onClick={resetErrorBoundary}>Try again</button>
    </div>
  );
}

// Wrap any subtree that might throw
<ErrorBoundary FallbackComponent={ErrorFallback} onError={logError}>
  <Suspense fallback={<Spinner />}>
    <AsyncComponent />
  </Suspense>
</ErrorBoundary>
```

### In Next.js App Router — error.tsx
```tsx
// app/dashboard/error.tsx — auto error boundary for the route segment
'use client';
export default function Error({ error, reset }: { error: Error; reset: () => void }) {
  return (
    <div>
      <h2>Something went wrong!</h2>
      <button onClick={reset}>Try again</button>
    </div>
  );
}
```

**Rules:**
- Wrap every `<Suspense>` in an `<ErrorBoundary>` — rejected promises throw
- Error boundaries don't catch: event handlers, async code, SSR errors, errors in the boundary itself
- Log errors to an error tracking service (Sentry, etc.) in the `onError` callback
- Always provide a `reset` mechanism so users can recover without refreshing

## Custom Hook Patterns

### useFetch — data fetching with loading/error state
```tsx
function useFetch<T>(url: string) {
  const [state, setState] = useState<{ data: T | null; loading: boolean; error: Error | null }>({
    data: null, loading: true, error: null
  });

  useEffect(() => {
    const controller = new AbortController();
    fetch(url, { signal: controller.signal })
      .then(r => { if (!r.ok) throw new Error(`HTTP ${r.status}`); return r.json(); })
      .then(data => setState({ data, loading: false, error: null }))
      .catch(err => {
        if (err.name !== 'AbortError') setState({ data: null, loading: false, error: err });
      });
    return () => controller.abort();
  }, [url]);

  return state;
}
```

### useLocalStorage — synced localStorage state
```tsx
function useLocalStorage<T>(key: string, initial: T) {
  const [value, setValue] = useState<T>(() => {
    try { return JSON.parse(localStorage.getItem(key) ?? '') as T; }
    catch { return initial; }
  });

  const set = useCallback((next: T | ((prev: T) => T)) => {
    const resolved = typeof next === 'function' ? (next as (p: T) => T)(value) : next;
    setValue(resolved);
    localStorage.setItem(key, JSON.stringify(resolved));
  }, [key, value]);

  return [value, set] as const;
}
```

### useDebounce — debounce rapidly changing values
```tsx
function useDebounce<T>(value: T, delay = 300): T {
  const [debounced, setDebounced] = useState(value);
  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);
  return debounced;
}
```

**Rules:**
- Name always starts with `use`
- Must be called at the top level — never inside conditions or loops
- Each hook = one well-named responsibility

## TanStack Query — Server State Management

### Setup
```tsx
// app/providers.tsx
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
const queryClient = new QueryClient({
  defaultOptions: { queries: { staleTime: 60_000, retry: 1 } }
});
export function Providers({ children }) {
  return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>;
}
```

### Query (GET)
```tsx
import { useQuery } from '@tanstack/react-query';

const userKeys = { all: ['users'] as const, detail: (id: string) => ['users', id] as const };

function UserProfile({ id }: { id: string }) {
  const { data: user, isPending, error } = useQuery({
    queryKey: userKeys.detail(id),
    queryFn: () => fetch(`/api/users/${id}`).then(r => r.json()),
  });

  if (isPending) return <Skeleton />;
  if (error) return <Error message={error.message} />;
  return <div>{user.name}</div>;
}
```

### Mutation (POST/PUT/DELETE)
```tsx
import { useMutation, useQueryClient } from '@tanstack/react-query';

function DeleteUserButton({ id }: { id: string }) {
  const queryClient = useQueryClient();
  const { mutate, isPending } = useMutation({
    mutationFn: (id: string) => fetch(`/api/users/${id}`, { method: 'DELETE' }),
    onSuccess: () => queryClient.invalidateQueries({ queryKey: userKeys.all }),
  });
  return <button onClick={() => mutate(id)} disabled={isPending}>Delete</button>;
}
```

**Rule:** Never store server data in `useState` + `useEffect`. That's TanStack Query's job.
